        h = (h * base) % prime;
    }

    for (let i = 0; i < m; i++) {
        patHash = (base * patHash + pattern.charCodeAt(i)) % prime;
        txtHash = (base * txtHash + text.charCodeAt(i)) % prime;
    }

    for (let i = 0; i <= n - m; i++) {
